kubectl exec -n mongodb mongodb-replica-0 -- mongosh 'mongodb://admin-user:admin123password@localhost:27017/admin?authSource=admin&directConnection=true' --quiet --eval "
var params = db.adminCommand({getParameter: 1, logLevel: 1});
var prof = db.adminCommand({profile: -1});
print('logLevel:', params.logLevel);
print('slowms:', prof.slowms);
" 2>&1

# Apply live settings to all 3 pods
for pod in mongodb-replica-0 mongodb-replica-1 mongodb-replica-2; do
  echo "=== Applying live settings to $pod ==="
  kubectl exec -n mongodb $pod -- mongosh 'mongodb://admin-user:admin123password@localhost:27017/admin?authSource=admin&directConnection=true' --quiet --eval "
    var r1 = db.adminCommand({setParameter: 1, logLevel: 1});
    var r2 = db.adminCommand({setParameter: 1, slowOpThresholdMs: 200});
    print('logLevel set:', r1.ok, '| slowOpThresholdMs set:', r2.ok);
  " 2>&1
done

# Check what the correct parameter name is for slowms
kubectl exec -n mongodb mongodb-replica-0 -- mongosh 'mongodb://admin-user:admin123password@localhost:27017/admin?authSource=admin&directConnection=true' --quiet --eval "
  // Try profile command to set slowms
  var r = db.adminCommand({profile: -1, slowms: 200});
  print(JSON.stringify(r));
" 2>&1

# profile: -1 returns state but doesn't change. Use profile: 0 to set slowms
kubectl exec -n mongodb mongodb-replica-0 -- mongosh 'mongodb://admin-user:admin123password@localhost:27017/admin?authSource=admin&directConnection=true' --quiet --eval "
  var r = db.adminCommand({profile: 0, slowms: 200});
  print(JSON.stringify(r));
  var check = db.adminCommand({profile: -1});
  print('after:', check.slowms);
" 2>&1

